// src/pages/SectionExperiences.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { experiencesService } from '../services/experiences';
import { authService } from '../services/auth';
import './SectionExperiences.css';

export default function SectionExperiences() {
  const navigate = useNavigate();
  const [items, setItems]     = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch]   = useState('');
  const [buying, setBuying]   = useState(null);

  const isAuthenticated = authService.isAuthenticated();
  const user            = authService.getUserFromStorage?.() || JSON.parse(localStorage.getItem('user') || 'null');

  useEffect(() => {
    experiencesService.getAll({ status: 'published' })
      .then(res => setItems(res.data.results ?? res.data))
      .catch(() => setItems(MOCK))
      .finally(() => setLoading(false));
  }, []);

  const filtered = items.filter(e =>
    !search ||
    e.title?.toLowerCase().includes(search.toLowerCase()) ||
    e.course_title?.toLowerCase().includes(search.toLowerCase()) ||
    e.section_title?.toLowerCase().includes(search.toLowerCase())
  );

  const handleBuy = async (exp) => {
    if (!isAuthenticated) { navigate('/login'); return; }
    setBuying(exp.id);
    try {
      await experiencesService.buy(exp.id);
      setItems(prev => prev.map(e =>
        e.id === exp.id ? { ...e, is_purchased: true } : e
      ));
      alert('✅ تم الشراء بنجاح!');
    } catch (err) {
      const msg = err.response?.data?.detail
                || err.response?.data?.[0]
                || 'حدث خطأ، حاول مرة أخرى';
      alert(`❌ ${msg}`);
    } finally {
      setBuying(null);
    }
  };

  if (loading) return (
    <div className="exp-loading">
      <div className="exp-spinner" />
      <p>جاري تحميل التجارب…</p>
    </div>
  );

  return (
    <div className="exp-page">

      {/* Hero */}
      <header className="exp-hero">
        <div className="exp-hero__inner">
          <span className="exp-eyebrow">Section Experiences</span>
          <h1 className="exp-hero__title">تجارب السكاشن</h1>
          <p className="exp-hero__sub">فاتك سكشن؟ اشتريه واشوف كيف اتحلّت المسائل خطوة بخطوة</p>
          <div className="exp-hero__actions">
            <input
              className="exp-search"
              placeholder="ابحث عن تجربة أو كورس..."
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
            {isAuthenticated && user?.is_instructor && (
              <button className="exp-btn-create" onClick={() => navigate('/experiences/create')}>
                + إضافة تجربة
              </button>
            )}
          </div>
        </div>
      </header>

      {/* Stats */}
      <div className="exp-stats-bar">
        <span>{items.length} تجربة متاحة</span>
        <span>•</span>
        <span>{items.filter(e => parseFloat(e.effective_price) === 0).length} مجانية</span>
        <span>•</span>
        <span>توزيع الأرباح بين المدرس والكلية</span>
      </div>

      {/* Grid */}
      <div className="exp-container">
        {filtered.length === 0 ? (
          <div className="exp-empty">لا توجد تجارب مطابقة</div>
        ) : (
          <div className="exp-grid">
            {filtered.map(exp => (
              <ExperienceCard
                key={exp.id}
                exp={exp}
                onBuy={() => handleBuy(exp)}
                buying={buying === exp.id}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Card ───────────────────────────────────────────────────────────────────────
function ExperienceCard({ exp, onBuy, buying }) {
  const isFree  = parseFloat(exp.effective_price) === 0;
  const [open, setOpen] = useState(false);

  // الـ API بيبعت image_url مش thumbnail_url
  const imgSrc = exp.image_url || exp.thumbnail_url || null;

  return (
    <div className={`exp-card ${exp.is_featured ? 'exp-card--featured' : ''}`}>

      {/* Image */}
      <div className="exp-card__img">
        {imgSrc
          ? <img src={imgSrc} alt={exp.title} />
          : <div className="exp-card__img-placeholder"><span>🧪</span></div>
        }
        {exp.is_featured    && <div className="exp-card__featured-badge">★ مميز</div>}
        {exp.discount_percent > 0 && (
          <div className="exp-card__discount-badge">-{exp.discount_percent}%</div>
        )}
        {exp.is_purchased   && <div className="exp-card__owned-badge">✓ مشترك</div>}
      </div>

      {/* Body */}
      <div className="exp-card__body">
        {exp.course_title  && <p className="exp-card__course">{exp.course_title}</p>}
        {exp.section_title && <p className="exp-card__section">📂 {exp.section_title}</p>}
        <h3 className="exp-card__title">{exp.title}</h3>
        {exp.description && (
          <p className="exp-card__desc">
            {exp.description.length > 100 ? exp.description.slice(0, 100) + '…' : exp.description}
          </p>
        )}
        {exp.instructor_name && (
          <p className="exp-card__instructor">👤 {exp.instructor_name}</p>
        )}

        {/* Preview */}
        {exp.preview_video_url && (
          <button className="exp-card__preview-btn" onClick={() => setOpen(o => !o)}>
            {open ? '▼ إخفاء المعاينة' : '▶ مشاهدة preview مجاني'}
          </button>
        )}
        {open && exp.preview_video_url && (
          <div className="exp-card__preview-video">
            <iframe src={exp.preview_video_url} title="preview"
              allow="autoplay; encrypted-media" allowFullScreen />
          </div>
        )}
      </div>

      {/* Footer */}
      <div className="exp-card__footer">
        <div className="exp-card__price-wrap">
          {isFree
            ? <span className="exp-price exp-price--free">مجاني</span>
            : <>
                <span className="exp-price">{exp.effective_price} EGP</span>
                {exp.discount_price && (
                  <span className="exp-price--old">{exp.price} EGP</span>
                )}
              </>
          }
          {exp.total_buyers > 0 && (
            <span className="exp-card__buyers">{exp.total_buyers} اشتروا</span>
          )}
        </div>

        {exp.is_purchased ? (
          <button className="exp-btn exp-btn--owned" disabled>✓ تملكها</button>
        ) : (
          <button className="exp-btn exp-btn--buy" onClick={onBuy} disabled={buying}>
            {buying ? '...' : isFree ? 'احصل عليها' : 'اشتري الآن'}
          </button>
        )}
      </div>
    </div>
  );
}

